class Solution:
    def findIntegers(self, n: int) -> int:
        if n == 0:
            return 1
        b = bin(n)[2:]
        length = len(b)
        dp = [0] * (length + 1)
        dp[0], dp[1] = 1, 1
        for i in range(2, length + 1):
            dp[i] = dp[i - 1] + dp[i - 2]
        result = 0
        prev_bit = 0
        for i in range(length):
            if b[i] == '1':
                result += dp[length - i]
                if prev_bit == 1:
                    return result
                prev_bit = 1
            else:
                prev_bit = 0
        return result + 1

